// Flag LLM attribution / placeholder comments AI tools leave behind:
// "Generated by Claude", "Created with ChatGPT", "AI-generated", etc.
// These ship to version control and look unprofessional; they should be stripped.

const ATTRIBUTION = [
  /\b(?:generated|created|written|authored)\s+(?:with|by|using)\s+(?:claude|chatgpt|gpt|copilot|gemini|cursor|ai|llm)\b/i,
  /\b(?:claude|chatgpt|gpt|copilot|gemini)\s+(?:wrote|generated|created)\b/i,
  /\bai[- ]?generated\b/i,
];

export default {
  meta: {
    type: 'suggestion',
    docs: { description: 'Disallow LLM attribution comments ("Generated by Claude", etc.).' },
    schema: [],
    messages: {
      llmArtifact: 'LLM attribution comment — remove it before committing.',
    },
  },
  create(context) {
    return {
      Program() {
        for (const comment of context.sourceCode.getAllComments()) {
          if (ATTRIBUTION.some((re) => re.test(comment.value))) {
            context.report({ loc: comment.loc, messageId: 'llmArtifact' });
          }
        }
      },
    };
  },
};
